const res = $json;
if (res.statusCode >= 400 || res.error || (res.headers && res.headers["www-authenticate"])) {
  const text = `⚠️ Token de Facebook.CodigoAlfa caducado o inválido.\n\n${
    res.headers["www-authenticate"] || res.error || ''
  }`
    .replace(/[_*[\]()~`>#+=|{}.!-]/g, ''); // elimina caracteres conflictivos

  return [
    {
      json: {
        notify: true,
        message: text
      }
    }
  ];
}
return [{ json: { notify: false } }];

