// Captura el objeto devuelto por el nodo Gmail
const error = $input.first().json.error

// Si existe error y contiene mensaje de credenciales
if (error && (
    error.includes('invalid') ||
    error.includes('expired') ||
    error.includes('revoked')
)) {
  return [
    {
      json: {
        notify: true,
        message: '⚠️ Credenciales de Google (gmail) caducadas o inválidas: ' + error
      }
    }
  ];
}

// Si todo está bien, continúa
